mapper.select:
SELECT r.RESERVATION_ID as "reservationId", m1.USERNAME as "guestName", m2.PHONE_NUMBER as "guestPhone", rm.ROOM_NAME as "roomName", TO_CHAR(r.CHECK_IN_DATE, 'YYYY-MM-DD') as "checkIn", TO_CHAR(r.CHECK_OUT_DATE, 'YYYY-MM-DD') as "checkOut", r.AMOUNT as "amount", r.GUEST_COUNT as "guestCount", r.STATUS as "status", TO_CHAR(r.REQUEST) as "requset" FROM RESERVATION r JOIN MEMBER1 m1 ON r.MEMBER_ID = m1.MEMBER_ID JOIN MEMBER2 m2 ON r.MEMBER_ID = m2.MEMBER_ID JOIN ROOM rm ON r.ROOM_ID = rm.ROOM_ID
rm.PLACE_ID = #{placeId}
AND r.ROOM_ID = #{roomId}
AND r.CHECK_IN_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND r.CHECK_IN_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND r.STATUS = #{status}
AND (m1.USERNAME LIKE '%' || #{keyword} || '%' OR m2.PHONE_NUMBER LIKE '%' || #{keyword} || '%')
ORDER BY r.RESERVATION_ID DESC
